import{_ as r,o as e,c as o,a2 as s}from"./chunks/framework.DqgtWGRo.js";const p=JSON.parse('{"title":"What is S0RA?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),i={name:"guide/index.md"};function d(a,t,n,l,g,c){return e(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="what-is-s0ra" tabindex="-1">What is S0RA? <a class="header-anchor" href="#what-is-s0ra" aria-label="Permalink to &quot;What is S0RA?&quot;">​</a></h1><p><strong>S0RA Agent</strong> is a standalone CLI application that mirrors the Hermes Agent architecture but focuses on <strong>real-time voice AI</strong> through multiple providers:</p><ul><li><strong>Gemini Live</strong> — Google&#39;s multimodal live API (Discord + VOIP)</li><li><strong>Vapi.ai</strong> — Managed conversational AI platform (Discord + Phone)</li><li><strong>ElevenLabs</strong> — High-quality TTS/Conversational AI (Discord)</li><li><strong>Edge TTS / OpenAI TTS / Whisper</strong> — Local/cloud TTS &amp; STT fallback</li></ul><h2 id="key-philosophy" tabindex="-1">Key Philosophy <a class="header-anchor" href="#key-philosophy" aria-label="Permalink to &quot;Key Philosophy&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Approach</th></tr></thead><tbody><tr><td><strong>Architecture</strong></td><td>Mirrors Hermes exactly (constants, config, logging, profiles, skins, plugins)</td></tr><tr><td><strong>Distribution</strong></td><td><code>pipx install git+https://...</code> — isolated, updatable, git-based</td></tr><tr><td><strong>Voice</strong></td><td>Provider toggle: switch TTS/STT/LLM Voice at runtime</td></tr><tr><td><strong>VOIP</strong></td><td>Asterisk ARI → RTP → Dograh → Gemini Live (phone calls, not Discord)</td></tr><tr><td><strong>MCP</strong></td><td>Auto-discovers local MCP servers (stdio + HTTP 3000-3010)</td></tr><tr><td><strong>Memory</strong></td><td>Detects Honcho, OpenClaw, Hermes memory — auto-configures passthrough</td></tr><tr><td><strong>Extensibility</strong></td><td>Plugin system compatible with Hermes plugins</td></tr><tr><td><strong>UI</strong></td><td>CLI + TUI (Ink/React) + Web Dashboard (React/Vite)</td></tr></tbody></table><h2 id="quick-comparison" tabindex="-1">Quick Comparison <a class="header-anchor" href="#quick-comparison" aria-label="Permalink to &quot;Quick Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Hermes</th><th>S0RA</th></tr></thead><tbody><tr><td>Primary Interface</td><td>Text chat</td><td><strong>Voice-first</strong> (Discord + VOIP)</td></tr><tr><td>Voice Providers</td><td>Discord only</td><td>Discord + <strong>Asterisk/SIP + Dograh</strong></td></tr><tr><td>Provider Toggle</td><td>No</td><td><strong>Yes</strong> (Gemini/Vapi/ElevenLabs/Edge/OpenAI/Whisper)</td></tr><tr><td>MCP</td><td>Yes</td><td>Yes + <strong>auto-discovery + WebSocket</strong></td></tr><tr><td>Installation</td><td><code>pipx install hermes-agent</code></td><td><code>pipx install git+...sora-agent</code></td></tr><tr><td>Updates</td><td>Git-based</td><td><strong>Git-based</strong></td></tr><tr><td>Web Dashboard</td><td>No</td><td><strong>Yes</strong> (live demo, provider toggles)</td></tr><tr><td>TUI</td><td>No</td><td><strong>Yes</strong> (Ink/React)</td></tr><tr><td>ACP Server</td><td>No</td><td><strong>Yes</strong></td></tr></tbody></table><h2 id="who-is-it-for" tabindex="-1">Who Is It For? <a class="header-anchor" href="#who-is-it-for" aria-label="Permalink to &quot;Who Is It For?&quot;">​</a></h2><ul><li><strong>Self-hosters</strong> with Asterisk + Dograh wanting phone-call AI</li><li><strong>Discord bot developers</strong> needing multi-provider voice bridges</li><li><strong>Hermes users</strong> wanting a voice-focused companion agent</li><li><strong>Anyone</strong> wanting a <code>hermes</code>-like CLI for voice AI that works standalone</li></ul>',9)])])}const u=r(i,[["render",d]]);export{p as __pageData,u as default};
